class Solution {
public:
    int getMinSwaps(string num, int k) {
        int n = num.size();
        vector<int> idx(n);
        for (int i = 0; i < n; i++) idx[i] = i;
        sort(idx.begin(), idx.end(), [&](int a, int b) {
            return num[a] < num[b];
        });
        int res = 0;
        for (int i = 0; i < n - 1; i++) {
            if (num[i] >= num[idx[i]]) continue;
            int j = i + 1;
            while (j < n && num[j] <= num[idx[i]]) j++;
            j--;
            swap(num[i], num[j]);
            swap(idx[i], idx[j]);
            res++;
            k--;
            if (k == 0) break;
        }
        return res;
    }
};
